int lcs(std::string s1, std::string s2) {
    int m = s1.size(), n = s2.size();
    std::vector<std::vector<int>> dp(m+1, std::vector<int>(n+1, 0));
    for (int i = 1; i <= m; i++)
        for (int j = 1; j <= n; j++)
            dp[i][j] = s1[i-1]==s2[j-1] ? dp[i-1][j-1]+1 : std::max(dp[i-1][j], dp[i][j-1]);
    return dp[m][n];
}

void bfs(std::vector<std::vector<int>>& graph, int start) {
    std::vector<bool> visited(graph.size(), false);
    std::queue<int> q;
    visited[start] = true;
    q.push(start);
    while (!q.empty()) {
        int node = q.front(); q.pop();
        for (int neighbor : graph[node])
            if (!visited[neighbor]) { visited[neighbor] = true; q.push(neighbor); }
    }
}

